/**
 * 番茄小说创作助手 - 预加载脚本入口
 * 
 * 暴露安全的 API 给渲染进程
 * 所有 API 通过 contextBridge 暴露
 */

import { contextBridge, ipcRenderer } from 'electron'

// 重新导出 preload.ts 的功能
// 保持统一的导入路径

/**
 * 暴露安全的 API 给渲染进程
 */
function exposeElectronAPI(): void {
  contextBridge.exposeInMainWorld('electronAPI', {
    // 对话框
    openDirectory: () => ipcRenderer.invoke('dialog:openDirectory'),

    // 文件系统 - 读取操作
    readFile: (filePath: string) => ipcRenderer.invoke('fs:readFile', filePath),
    exists: (filePath: string) => ipcRenderer.invoke('fs:exists', filePath),
    readdir: (dirPath: string) => ipcRenderer.invoke('fs:readdir', dirPath),

    // 文件系统 - 写入操作
    writeFile: (filePath: string, content: string) => 
      ipcRenderer.invoke('fs:writeFile', filePath, content),
    mkdir: (dirPath: string) => ipcRenderer.invoke('fs:mkdir', dirPath),

    // 文件系统 - 删除操作
    unlink: (filePath: string) => ipcRenderer.invoke('fs:unlink', filePath),
    rmdir: (dirPath: string, options?: { recursive?: boolean }) => 
      ipcRenderer.invoke('fs:rmdir', dirPath, options),
    remove: (targetPath: string) => ipcRenderer.invoke('fs:remove', targetPath),

    // 便捷删除方法
    deleteFile: (filePath: string) => ipcRenderer.invoke('fs:unlink', filePath),
    deleteDirectory: (dirPath: string) => ipcRenderer.invoke('fs:rmdir', dirPath, { recursive: true }),
    renameFile: (oldPath: string, newPath: string) => ipcRenderer.invoke('fs:rename', oldPath, newPath),

    // 系统
    openPath: (path: string) => ipcRenderer.invoke('shell:openPath', path),

    // 项目
    getProjectRoot: () => ipcRenderer.invoke('project:getRoot'),
    setProjectRoot: (rootPath: string) => ipcRenderer.invoke('project:setRoot', rootPath),

    // 文件系统监听
    fsWatch: (dirPath?: string) => ipcRenderer.invoke('fs:watch', dirPath),
    fsUnwatch: () => ipcRenderer.invoke('fs:unwatch'),
    onFsChange: (callback: (data: { type: string; fileName: string; path: string }) => void) => {
      const handler = (_event: any, data: any) => callback(data)
      ipcRenderer.on('fs:change', handler)
      return () => ipcRenderer.removeListener('fs:change', handler)
    },

    // 安全存储 - 用于加密存储 API Key 等敏感信息
    safeStorage: {
      encrypt: (plainText: string) => ipcRenderer.invoke('safeStorage:encrypt', plainText),
      decrypt: (encrypted: Uint8Array | number[]) => ipcRenderer.invoke('safeStorage:decrypt', Array.from(encrypted)),
      isAvailable: () => ipcRenderer.invoke('safeStorage:isAvailable'),
    },

    // ==================== YAML 服务 API ====================
    yaml: {
      read: (filePath: string) => ipcRenderer.invoke('yaml:read', filePath),
      write: (filePath: string, data: any) => ipcRenderer.invoke('yaml:write', filePath, data),
    },

    // ==================== AI 服务 API ====================

    // AI Key 管理
    ai: {
      saveApiKey: (service: string, apiKey: string) => 
        ipcRenderer.invoke('ai:saveApiKey', service, apiKey),

      isConfigured: (service: string) => 
        ipcRenderer.invoke('ai:isConfigured', service),

      getConfiguredServices: () => 
        ipcRenderer.invoke('ai:getConfiguredServices'),

      call: (prompt: string, options?: any) => 
        ipcRenderer.invoke('ai:call', prompt, options),

      stream: (prompt: string, options?: any) => 
        ipcRenderer.invoke('ai:stream', prompt, options),

      onStreamChunk: (callback: (chunk: { content: string; done: boolean; reasoning?: string }) => void) => {
        const handler = (_event: any, chunk: any) => callback(chunk as { content: string; done: boolean; reasoning?: string })
        ipcRenderer.on('ai:stream-chunk', handler)
        return () => ipcRenderer.removeListener('ai:stream-chunk', handler)
      },

      onStreamError: (callback: (error: string) => void) => {
        const handler = (_event: any, error: any) => callback(error as string)
        ipcRenderer.on('ai:stream-error', handler)
        return () => ipcRenderer.removeListener('ai:stream-error', handler)
      },

      testConnection: (service: string) => 
        ipcRenderer.invoke('ai:testConnection', service),

      saveSetting: (key: string, value: any) => 
        ipcRenderer.invoke('ai:saveSetting', key, value),

      getSetting: (key: string, defaultValue?: any) => 
        ipcRenderer.invoke('ai:getSetting', key, defaultValue),
    },

    // ==================== 备份服务 API ====================

    backup: {
      create: (projectPath: string) => ipcRenderer.invoke('backup:create', projectPath),
      list: () => ipcRenderer.invoke('backup:list'),
      restore: (backupPath: string, targetPath: string) => ipcRenderer.invoke('backup:restore', backupPath, targetPath),
      delete: (backupPath: string) => ipcRenderer.invoke('backup:delete', backupPath),
    },
  })
}

/**
 * 初始化预加载 API
 */
function init(): void {
  exposeElectronAPI()
}

// 立即初始化
init()

// 为 TypeScript 声明全局类型
export type ElectronAPI = {
  openDirectory: () => Promise<string | undefined>
  readFile: (filePath: string) => Promise<{success: boolean; content?: string; error?: string}>
  exists: (filePath: string) => Promise<{success: boolean; exists?: boolean; error?: string}>
  readdir: (dirPath: string) => Promise<{success: boolean; data?: Array<{name: string; isDirectory: boolean; isFile: boolean}>; error?: string}>
  writeFile: (filePath: string, content: string) => Promise<{success: boolean; error?: string}>
  mkdir: (dirPath: string) => Promise<{success: boolean; error?: string}>
  unlink: (filePath: string) => Promise<{success: boolean; error?: string}>
  rmdir: (dirPath: string, options?: { recursive?: boolean }) => Promise<{success: boolean; error?: string}>
  remove: (targetPath: string) => Promise<{success: boolean; error?: string}>
  deleteFile: (filePath: string) => Promise<{success: boolean; error?: string}>
  deleteDirectory: (dirPath: string) => Promise<{success: boolean; error?: string}>
  renameFile: (oldPath: string, newPath: string) => Promise<{success: boolean; error?: string}>
  openPath: (path: string) => Promise<string>
  getProjectRoot: () => Promise<string | null>
  fsWatch: (dirPath?: string) => Promise<{ success: boolean; path?: string; error?: string }>
  fsUnwatch: () => Promise<{ success: boolean; error?: string }>
  onFsChange: (callback: (data: { type: string; fileName: string; path: string }) => void) => () => void
  safeStorage: {
    encrypt: (plainText: string) => Promise<{success: boolean; data?: Buffer; error?: string}>
    decrypt: (encrypted: Buffer) => Promise<{success: boolean; data?: string; error?: string}>
    isAvailable: () => Promise<{success: boolean; available?: boolean; error?: string}>
  }
  yaml: {
    read: (filePath: string) => Promise<{success: boolean; data?: any; error?: string}>
    write: (filePath: string, data: any) => Promise<{success: boolean; error?: string}>
  }
  ai: {
    saveApiKey: (service: string, apiKey: string) => Promise<{success: boolean; error?: string}>
    isConfigured: (service: string) => Promise<{success: boolean; configured?: boolean; error?: string}>
    getConfiguredServices: () => Promise<{success: boolean; services?: string[]; error?: string}>
    call: (prompt: string, options?: any) => Promise<{success: boolean; content?: string; error?: string}>
    stream: (prompt: string, options?: any) => Promise<{success: boolean; error?: string}>
    onStreamChunk: (callback: (chunk: { content: string; done: boolean; reasoning?: string }) => void) => () => void
    onStreamError: (callback: (error: string) => void) => () => void
    testConnection: (service: string) => Promise<{success: boolean; result?: boolean; error?: string}>
    saveSetting: (key: string, value: any) => Promise<{success: boolean; error?: string}>
    getSetting: (key: string, defaultValue?: any) => Promise<{success: boolean; value?: any; error?: string}>
  }
  backup: {
    create: (projectPath: string) => Promise<{success: boolean; backupPath?: string; error?: string}>
    list: () => Promise<{success: boolean; backups?: Array<{name: string; path: string; date: string; size: number}>; error?: string}>
    restore: (backupPath: string, targetPath: string) => Promise<{success: boolean; error?: string}>
    delete: (backupPath: string) => Promise<{success: boolean; error?: string}>
  }
}

declare global {
  interface Window {
    electronAPI: ElectronAPI
  }
}
